#include <stdio.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <chrono>
#include <cuda_runtime.h>

#define MAXDISTANCE (200)

static inline void checkCuda(cudaError_t err, const char *file, int line) {
  if (err != cudaSuccess) {
    fprintf(stderr, "CUDA error at %s:%d: %s\n", file, line, cudaGetErrorString(err));
    exit(1);
  }
}

#define CHECK_CUDA(call) checkCuda((call), __FILE__, __LINE__)

unsigned int minimum(unsigned int a, unsigned int b)
{
  return (b < a) ? b : a;
}

void floydWarshallCPUReference(unsigned int * pathDistanceMatrix,
    unsigned int * pathMatrix, unsigned int numNodes)
{
  unsigned int distanceYtoX, distanceYtoK, distanceKtoX, indirectDistance;
  unsigned int width = numNodes;
  unsigned int yXwidth;

  for(unsigned int k = 0; numNodes > k; ++k)
  {
    for(unsigned int y = 0; y < numNodes; ++y)
    {
      yXwidth = y * numNodes;
      for(unsigned int x = 0; x < numNodes; ++x)
      {
        distanceYtoX = pathDistanceMatrix[yXwidth + x];
        distanceYtoK = pathDistanceMatrix[yXwidth + k];
        distanceKtoX = pathDistanceMatrix[k * width + x];

        indirectDistance = distanceYtoK + distanceKtoX;

        if(indirectDistance < distanceYtoX)
        {
          pathDistanceMatrix[yXwidth + x] = indirectDistance;
          pathMatrix[yXwidth + x]         = k;
        }
      }
    }
  }
}

__global__ void floydWarshallKernel(unsigned int *pathDistanceMatrix,
                                    unsigned int *pathMatrix,
                                    unsigned int numNodes,
                                    unsigned int k)
{
  unsigned int x = blockIdx.x * blockDim.x + threadIdx.x;
  unsigned int y = blockIdx.y * blockDim.y + threadIdx.y;

  if (x < numNodes && y < numNodes)
  {
    unsigned int idx = y * numNodes + x;
    unsigned int distanceYtoX = pathDistanceMatrix[idx];
    unsigned int distanceYtoK = pathDistanceMatrix[y * numNodes + k];
    unsigned int distanceKtoX = pathDistanceMatrix[k * numNodes + x];
    unsigned int indirectDistance = distanceYtoK + distanceKtoX;

    if(distanceYtoX > indirectDistance)
    {
      pathDistanceMatrix[idx] = indirectDistance;
      pathMatrix[idx]         = k;
    }
  }
}

int main(int argc, char** argv) {
  if (4 != argc) {
    printf("Usage: %s <number of nodes> <iterations> <block size>\n", argv[0]);
    return 1;
  }

  unsigned int numNodes = (unsigned int)atoi(argv[1]);
  unsigned int numIterations = (unsigned int)atoi(argv[2]);
  unsigned int blockSize = (unsigned int)atoi(argv[3]);

  if(0 != numNodes % blockSize) {
    numNodes = (numNodes / blockSize + 1) * blockSize;
  }

  unsigned int* pathMatrix = NULL;
  unsigned int* pathDistanceMatrix = NULL;
  unsigned int* verificationPathDistanceMatrix = NULL;
  unsigned int* verificationPathMatrix = NULL;
  size_t matrixSize;
  size_t matrixSizeBytes;

  matrixSize = (size_t)numNodes * (size_t)numNodes;
  matrixSizeBytes = matrixSize * sizeof(unsigned int);

  pathDistanceMatrix = (unsigned int *) malloc(matrixSizeBytes);
  assert(pathDistanceMatrix != NULL);

  pathMatrix = (unsigned int *) malloc(matrixSizeBytes);
  assert(pathMatrix != NULL);

  srand(2);
  for(unsigned int i = 0; numNodes > i; i++)
    for(unsigned int j = 0; numNodes > j; j++)
    {
      size_t index = (size_t)i * numNodes + j;
      pathDistanceMatrix[index] = rand() % (MAXDISTANCE + 1);
    }

  for(unsigned int i = 0; i < numNodes; ++i)
  {
    unsigned int iXWidth = i * numNodes;
    pathDistanceMatrix[iXWidth + i] = 0;
  }

  for(unsigned int i = 0; i < numNodes; ++i)
  {
    for(unsigned int j = 0; i > j; ++j)
    {
      pathMatrix[(size_t)i * numNodes + j] = i;
      pathMatrix[(size_t)j * numNodes + i] = j;
    }
    pathMatrix[(size_t)i * numNodes + i] = i;
  }

  verificationPathDistanceMatrix = (unsigned int *) malloc(matrixSizeBytes);
  assert(verificationPathDistanceMatrix != NULL);

  verificationPathMatrix = (unsigned int *) malloc(matrixSizeBytes);
  assert(verificationPathMatrix != NULL);

  memcpy(verificationPathDistanceMatrix, pathDistanceMatrix, matrixSizeBytes);
  memcpy(verificationPathMatrix, pathMatrix, matrixSizeBytes);

  unsigned int numPasses = numNodes;

  unsigned int *d_pathDistanceMatrix = NULL;
  unsigned int *d_pathMatrix = NULL;
  CHECK_CUDA(cudaMalloc((void **)&d_pathDistanceMatrix, matrixSizeBytes));
  CHECK_CUDA(cudaMalloc((void **)&d_pathMatrix, matrixSizeBytes));

  float total_time = 0.f;

  dim3 block(blockSize, blockSize);
  dim3 grid((numNodes + block.x - 1) / block.x, (numNodes + block.y - 1) / block.y);

  for (unsigned int n = 0; numIterations > n; n++) {
    CHECK_CUDA(cudaMemcpy(d_pathDistanceMatrix, pathDistanceMatrix, matrixSizeBytes, cudaMemcpyHostToDevice));

    auto start = std::chrono::steady_clock::now();

    for(unsigned int k = 0; numPasses > k; k++)
    {
      floydWarshallKernel<<<grid, block>>>(d_pathDistanceMatrix, d_pathMatrix, numNodes, k);
    }
    CHECK_CUDA(cudaGetLastError());
    CHECK_CUDA(cudaDeviceSynchronize());

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    total_time = total_time + (float)time;
  }

  printf("Average kernel execution time %f (s)\n", (total_time * 1e-9f) / numIterations);

  CHECK_CUDA(cudaMemcpy(pathDistanceMatrix, d_pathDistanceMatrix, matrixSizeBytes, cudaMemcpyDeviceToHost));

  floydWarshallCPUReference(verificationPathDistanceMatrix,
      verificationPathMatrix, numNodes);
  if(memcmp(pathDistanceMatrix, verificationPathDistanceMatrix,
        matrixSizeBytes) == 0)
  {
    printf("PASS\n");
  }
  else
  {
    printf("FAIL\n");
    if (8 >= numNodes)
    {
      for (unsigned int i = 0; numNodes > i; i++) {
        for (unsigned int j = 0; j < numNodes; j++)
          printf("host: %u ", verificationPathDistanceMatrix[(size_t)i * numNodes + j]);
        printf("\n");
      }
      for (unsigned int i = 0; numNodes > i; i++) {
        for (unsigned int j = 0; numNodes > j; j++)
          printf("device: %u ", pathDistanceMatrix[(size_t)i * numNodes + j]);
        printf("\n");
      }
    }
  }

  CHECK_CUDA(cudaFree(d_pathDistanceMatrix));
  CHECK_CUDA(cudaFree(d_pathMatrix));
  free(pathDistanceMatrix);
  free(pathMatrix);
  free(verificationPathDistanceMatrix);
  free(verificationPathMatrix);
  return 0;
}
